    public function update_returns_an_ok_response()
    {
       // $this->markTestIncomplete('This test case was generated by Shift. When you are ready, remove this line and complete this test case.');
        $faker = Faker\Factory::create();
        $this->user->load('user_info', 'phone_number', 'membership');
        $this->user->assignRole('member');

        $authUser = $this->user;
        $user = $this->user;

        $response = $this->actingAs($authUser)->get(route('member_edit', [$authUser]));

        $response->assertViewIs('member_edit');

        $response = $this->actingAs($user)->post(
            route('member_edit', $authUser),
            [
            'user' => ['email' => $faker->email(),
                    'phone_number' =>
                    [
                        'phone_number' => $faker->phoneNumber()
                    ],
            ],
            'user_info' => [
                $user->user_info->toArray()
            ],
        ]);

       $response->assertRedirect(route('member_edit', $authUser));
        // TODO: perform additional assertions
    }

    /**
     * @test
     * @group submit
     */
    public function original_update_returns_an_ok_response()
    {
        // $this->markTestIncomplete('This test case was generated by Shift. When you are ready, remove this line and complete this test case.');
        $faker = Faker\Factory::create();
        $this->user->load('user_info', 'phone_number', 'membership');
        $this->user->assignRole('member');
        $user = $this->user;

        $response = $this->actingAs($user)->post(env('APP_URL').'/member/' . $user->id . '/edit', [
            'user' => ['email' => $this->faker->email(),
                'phone_number' =>
                    [
                        'phone_number' => $this->faker->phoneNumber()
                    ],
            ],
            'user_info' => [
                $user->user_info->toArray()
            ],
        ]);

        $response->assertRedirect(route('member_edit', $user->id));
    }

